final:
module async_up_counter_3bit(
    input clk,
    input rst,
    output [2:0] count
);

    reg [2:0] decrement_reg;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            decrement_reg <= 3'b000;
        end else begin
            decrement_reg <= decrement_reg + 1;
        end
    end

    assign count = decrement_reg;

endmodule
